// YouTube RSS XML 파싱
var raw = $input.first().json;
var xml = typeof raw === 'string' ? raw : (raw.body || JSON.stringify(raw));

// videoId, title, published 추출
var videoIdRegex = /<yt:videoId>([^<]+)<\/yt:videoId>/g;
var titleRegex = /<title>([^<]+)<\/title>/g;
var publishedRegex = /<published>([^<]+)<\/published>/g;
var thumbRegex = /<media:thumbnail[^>]*url="([^"]+)"/g;
var descRegex = /<media:description>([\s\S]*?)<\/media:description>/g;

var videoIds = [];
var titles = [];
var publishedDates = [];
var thumbUrls = [];
var descriptions = [];

var m;
while ((m = videoIdRegex.exec(xml)) !== null) videoIds.push(m[1].trim());
while ((m = titleRegex.exec(xml)) !== null) titles.push(m[1].trim());
while ((m = publishedRegex.exec(xml)) !== null) publishedDates.push(m[1].trim());
while ((m = thumbRegex.exec(xml)) !== null) thumbUrls.push(m[1].trim());
while ((m = descRegex.exec(xml)) !== null) {
  var desc = m[1].trim();
  // HTML 엔티티 디코딩 (기본)
  desc = desc.replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&').replace(/&quot;/g, '"').replace(/&#39;/g, "'");
  descriptions.push(desc);
}

// 채널 제목(첫 번째 title)은 스킵
var startIdx = (titles[0] && titles[0].indexOf('PRESSCO') >= 0) ? 1 : 1;

var videos = [];
for (var i = 0; i < videoIds.length; i++) {
  videos.push({
    video_id: videoIds[i],
    title: titles[i + startIdx] || titles[i] || '',
    published_at: publishedDates[i] || new Date().toISOString(),
    thumbnail_url: thumbUrls[i] || 'https://img.youtube.com/vi/' + videoIds[i] + '/sddefault.jpg',
    description: descriptions[i] || ''
  });
}

if (videos.length === 0) {
  throw new Error('YouTube RSS: no videos found');
}

return [{ json: { videos: videos, count: videos.length } }];

// 신규 영상 감지
var rssData = $('Parse RSS').first().json;
var existingResp = $input.first().json;

var rssVideos = rssData.videos || [];
var existing = (existingResp && existingResp.list) ? existingResp.list : [];

var existingIds = {};
for (var i = 0; i < existing.length; i++) {
  existingIds[existing[i].video_id] = existing[i].Id;
}

var newVideos = [];
var updateVideos = [];

for (var j = 0; j < rssVideos.length; j++) {
  var v = rssVideos[j];
  if (!existingIds[v.video_id]) {
    newVideos.push(v);
  } else {
    // 기존 영상은 통계 업데이트 대상
    updateVideos.push({ id: existingIds[v.video_id], video_id: v.video_id });
  }
}

return [{ json: { newVideos, updateVideos, hasNew: newVideos.length > 0 } }];

// YouTube API 결과로 영상 데이터 보강 + URL/키워드 파싱
var ytResp = $input.first().json;
var newVideosData = $('Find New Videos').first().json;
var rssMap = {};
var rssVideos = $('Parse RSS').first().json.videos || [];
for (var i = 0; i < rssVideos.length; i++) {
  rssMap[rssVideos[i].video_id] = rssVideos[i];
}

// YouTube API 결과 맵
var ytMap = {};
var ytItems = (ytResp && ytResp.items) ? ytResp.items : [];
for (var j = 0; j < ytItems.length; j++) {
  var item = ytItems[j];
  ytMap[item.id] = item;
}

// foreverlove URL 파싱 정규식
var URL_REGEX = /https?:\/\/(?:www\.)?foreverlove\.co\.kr\/shop\/shopdetail\.html\?[^\s"<>]*branduid=(\d+)/gi;

var CATEGORY_MAP = { '압화': ['압화', '프레스드', '건조꽃', '하바리움', '부케', '꽃다발', '드라이플라워', 'herbarium', 'pressed flower'], '레진': ['레진', 'uv레진', '에폭시', '몰드', 'resin'], '캔들': ['캔들', '왁스', '향초', 'candle'], '석고': ['석고', '방향제'], '비즈': ['비즈', '구슬'] };

function detectCategory(text) {
  var t = (text || '').toLowerCase();
  for (var cat in CATEGORY_MAP) {
    var words = CATEGORY_MAP[cat];
    for (var k = 0; k < words.length; k++) {
      if (t.indexOf(words[k]) >= 0) return cat;
    }
  }
  return '';
}

var processedVideos = [];
var newVideos = newVideosData.newVideos || [];

for (var n = 0; n < newVideos.length; n++) {
  var rssV = rssMap[newVideos[n].video_id] || newVideos[n];
  var ytV = ytMap[rssV.video_id];

  var title = (ytV && ytV.snippet && ytV.snippet.title) ? ytV.snippet.title : rssV.title;
  var description = (ytV && ytV.snippet && ytV.snippet.description) ? ytV.snippet.description : (rssV.description || '');
  var tags = (ytV && ytV.snippet && ytV.snippet.tags) ? ytV.snippet.tags : [];
  var viewCount = (ytV && ytV.statistics && ytV.statistics.viewCount) ? parseInt(ytV.statistics.viewCount) : 0;
  var publishedAt = (ytV && ytV.snippet && ytV.snippet.publishedAt) ? ytV.snippet.publishedAt : rssV.published_at;
  var thumbnail = 'https://img.youtube.com/vi/' + rssV.video_id + '/sddefault.jpg';

  // URL 직접 매칭 (description에서 branduid 추출)
  var directBranduids = [];
  var urlMatch;
  var tmpDesc = description;
  URL_REGEX.lastIndex = 0;
  while ((urlMatch = URL_REGEX.exec(tmpDesc)) !== null) {
    if (directBranduids.indexOf(urlMatch[1]) < 0) directBranduids.push(urlMatch[1]);
  }

  // 카테고리 감지
  var allText = title + ' ' + description + ' ' + tags.join(' ');
  var matchedCategory = detectCategory(allText);

  processedVideos.push({
    video_id: rssV.video_id,
    title: title,
    description: description.substring(0, 2000),
    tags: JSON.stringify(tags),
    thumbnail_url: thumbnail,
    view_count: viewCount,
    published_at: publishedAt,
    synced_at: new Date().toISOString(),
    product_count: 0,
    matched_category: matchedCategory,
    status: 'active',
    // 매칭 데이터 (워크플로우 내 참조용)
    _directBranduids: directBranduids,
    _allText: allText
  });
}

return [{ json: { processedVideos, count: processedVideos.length } }];

// URL 직접 매칭 + 키워드 매칭으로 tbl_VideoProducts 레코드 생성
var processed = $('Process New Videos').first().json;
var videos = processed.processedVideos || [];

// 키워드 → 카테고리 매핑
var KEYWORDS = { '압화':['압화','프레스드플라워','하바리움','부케','드라이플라워','꽃다발','건조꽃'], '레진':['레진','UV레진','에폭시레진','몰드','레지너스'], '캔들':['캔들','왁스','소이왁스','향초'], '석고':['석고방향제','석고','아로마'], '비즈':['비즈','구슬','비즈공예'] };

// score 계산 함수 (제목에 포함=3, 태그에 포함=2, 설명에 포함=1)
function scoreKeyword(keyword, video) {
  var kw = keyword.toLowerCase();
  var score = 0;
  if ((video.title || '').toLowerCase().indexOf(kw) >= 0) score += 3;
  var tags = [];
  try { tags = JSON.parse(video.tags || '[]'); } catch(e) {}
  if (tags.join(' ').toLowerCase().indexOf(kw) >= 0) score += 2;
  if ((video.description || '').toLowerCase().indexOf(kw) >= 0) score += 1;
  return score;
}

var videoProductRequests = [];
for (var i = 0; i < videos.length; i++) {
  var v = videos[i];
  var directBranduids = v._directBranduids || [];

  // URL 직접 매칭 레코드
  for (var d = 0; d < directBranduids.length; d++) {
    videoProductRequests.push({
      video_id: v.video_id,
      branduid: directBranduids[d],
      product_name: '',
      product_price: 0,
      product_image: '',
      product_url: '/shop/shopdetail.html?branduid=' + directBranduids[d],
      source: 'description',
      confidence: 'high',
      match_score: 100,
      display_order: d + 1,
      is_active: true,
      matched_at: new Date().toISOString()
    });
  }

  // 키워드 매칭 (직접 매칭 없을 때만)
  if (directBranduids.length === 0) {
    var detectedKws = [];
    for (var cat in KEYWORDS) {
      var words = KEYWORDS[cat];
      for (var k = 0; k < words.length; k++) {
        var sc = scoreKeyword(words[k], v);
        if (sc > 0) detectedKws.push({ keyword: words[k], category: cat, score: sc });
      }
    }
    detectedKws.sort(function(a, b) { return b.score - a.score; });

    // 키워드 기반 상품 매칭은 tbl_Products 조회가 필요하지만
    // 이 Code 노드에서는 HTTP 호출 불가 → 키워드 정보만 저장
    // matched_category는 이미 video에 설정됨
    v._topKeywords = detectedKws.slice(0, 3).map(function(kw) { return kw.keyword; });
  }
}

return [{ json: { videoProductRequests, directMatchCount: videoProductRequests.length, videos: videos } }];

// 키워드 매칭으로 VideoProducts 레코드 완성
var matchData = $('Match Products').first().json;
var productsResp = $input.first().json;

var allProducts = (productsResp && productsResp.list) ? productsResp.list : [];
var directRequests = matchData.videoProductRequests || [];
var videos = matchData.videos || [];

// 이미 URL 직접 매칭된 video_id 목록
var directVideoIds = {};
for (var r = 0; r < directRequests.length; r++) {
  directVideoIds[directRequests[r].video_id] = true;
}

// 상품 키워드 인덱스 구축
var productKeywords = {};
for (var p = 0; p < allProducts.length; p++) {
  var prod = allProducts[p];
  var kws = [];
  try { kws = JSON.parse(prod.keywords || '[]'); } catch(e) {}
  productKeywords[prod.branduid] = {
    keywords: kws,
    product: prod
  };
}

var keywordMatchRequests = [];

for (var i = 0; i < videos.length; i++) {
  var v = videos[i];
  if (directVideoIds[v.video_id]) continue; // 이미 URL 직접 매칭

  var topKws = v._topKeywords || [];
  var matchedProducts = [];

  for (var j = 0; j < allProducts.length; j++) {
    var prod = allProducts[j];
    var prodName = (prod.product_name || '').toLowerCase();
    var score = 0;

    for (var k = 0; k < topKws.length; k++) {
      if (prodName.indexOf(topKws[k].toLowerCase()) >= 0) score += 2;
    }
    if ((v.matched_category || '') && prodName.indexOf(v.matched_category.toLowerCase()) >= 0) score += 3;
    var catName = prod.category_name || '';
    if (catName && catName === v.matched_category) score += 1;

    if (score > 0) matchedProducts.push({ score, prod });
  }

  // 점수 순 정렬, 상위 4개
  matchedProducts.sort(function(a, b) { return b.score - a.score; });
  matchedProducts = matchedProducts.slice(0, 4);

  for (var m = 0; m < matchedProducts.length; m++) {
    var mp = matchedProducts[m];
    keywordMatchRequests.push({
      video_id: v.video_id,
      branduid: mp.prod.branduid,
      product_name: mp.prod.product_name || '',
      product_price: mp.prod.price || 0,
      product_image: mp.prod.image_url || '',
      product_url: mp.prod.product_url || '/shop/shopdetail.html?branduid=' + mp.prod.branduid,
      source: 'keyword',
      confidence: 'medium',
      match_score: mp.score,
      display_order: m + 1,
      is_active: true,
      matched_at: new Date().toISOString()
    });
  }
}

var allRequests = directRequests.concat(keywordMatchRequests);
return [{ json: { allRequests, count: allRequests.length } }];
